#include <bits/stdc++.h>
using namespace std;
long long m,d,n,st[200010][50],a[200010],t=0;
long long solve(int l) {
    int k =log2(l);
    return max(st[n - l + 1][k], st[n - (1 << k) + 1][k]);
}
void add(long long x)
{
    st[++n][0]=x;
    for(int i=1;(1<<i)<=n;i++)
    {
        int l=n-(1<<i)+1;
        st[l][i]=max(st[l][i-1],st[l+(1<<(i-1))][i-1]);
    }
}
int main()
{
    ios::sync_with_stdio(0);
    cin.tie(0),cout.tie(0);
	cin>>m>>d;
	while(m--)
    {
        string s;
        long long x;
        cin>>s>>x;
        if(s[0]=='A')
        {
            add((x+t)%d);
        }
        else cout<<(t=solve(x))<<'\n';
    }
	return 0;
}
